use std::fs;
use std::path::PathBuf;
use std::process::Command;

use anyhow::{bail, Context, Result};

use crate::aot_c::{numeric_loop_kernel, NUMERIC_RUNTIME_HELPERS_C};

/// Tier B: the certified numeric-loop class compiled to wasm32 through
/// clang — the C lane's kernels wrapped in a FREESTANDING shell (no
/// libc, no libm, no WASI) that exports the gnosis `scalar-v1` ABI.
///
/// This lane is never a correctness dependency: Tier A (`aot_wasm.rs`,
/// direct wasm-encoder emission) covers the same class with zero
/// toolchain requirements. Tier B exists as (a) an independent
/// cross-check of Tier A output — two unrelated compilation pipelines
/// agreeing on the walker's semantics — and (b) the breadth lane that
/// widens for free whenever the C kernel emitter grows, ahead of the
/// hand-built wasm-encoder emitter catching up.
///
/// Decline discipline: `decline = trap`. Every `exit(3)` in the shared
/// kernel helpers becomes `__builtin_trap()` (wasm `unreachable`), and
/// implicit JS `undefined` traps at entry and helper alike — identical
/// observable behavior to Tier A modules under the same manifest
/// (`decline_semantics: "trap"`).
///
/// Semantics notes (why this preamble exists at all):
/// - Compiled with `-fno-builtin -nostdlib`, so every math name the
///   kernels reference is OURS: fabs/trunc/floor/ceil/sqrt map to
///   clang builtins (single wasm instructions, IEEE-identical to the
///   walker), while fmod/round/fmin/fmax get the SAME restricted /
///   walker-mirroring definitions Tier A uses (`__js_mod`,
///   half-away-from-zero round, NaN-ignoring min/max) — NOT libm.
/// - The bitwise family keeps the C lane's |x| < 2^32 decline fences
///   (kernel-level), so this lane declines where Tier A answers; the
///   parity contract is only ever against the walker.
pub fn emit_freestanding_wasm_c(source: &str, export_name: &str) -> Option<String> {
    let kernel = numeric_loop_kernel(source, export_name)?;
    let (entry_params, call) = if kernel.entry_arity == 0 {
        ("void".to_string(), format!("f_{export_name}()"))
    } else {
        ("double arg0".to_string(), format!("f_{export_name}(arg0)"))
    };

    Some(format!(
        r#"/* Freestanding wasm32 shell for the certified numeric-loop kernel.
   No libc, no libm, no WASI: zero imports by construction. Compiled
   with -fno-builtin -nostdlib; every referenced math name is defined
   below with walker-mirroring semantics. Decline = trap. */

#define exit(code) __builtin_trap()
#define GNOSIS_IMPLICIT_UNDEFINED() __builtin_trap()
#define GNOSIS_HELPER_UNDEFINED() __builtin_trap()

static double fabs(double x) {{ return __builtin_fabs(x); }}
static double trunc(double x) {{ return __builtin_trunc(x); }}
static double floor(double x) {{ return __builtin_floor(x); }}
static double ceil(double x) {{ return __builtin_ceil(x); }}
static double sqrt(double x) {{ return __builtin_sqrt(x); }}
/* Math.round: half away from zero (Rust f64::round / libm round),
   built from trunc + exact fraction compare — NOT f64.nearest, which
   is round-half-even and diverges at *.5. */
static double round(double x) {{
  if (x != x) return x;
  double r = __builtin_trunc(x);
  double f = x - r;
  if (f >= 0.5) return r + 1.0;
  if (f <= -0.5) return r - 1.0;
  return r;
}}
/* NaN-ignoring min/max (Rust f64::min/max semantics), NOT the
   NaN-propagating wasm f64.min/max clang would lower fmin/fmax to. */
static double fmin(double a, double b) {{
  if (a != a) return b;
  if (b != b) return a;
  return a < b ? a : b;
}}
static double fmax(double a, double b) {{
  if (a != a) return b;
  if (b != b) return a;
  return a > b ? a : b;
}}
/* JS % on the certified domain: integral operands with |x| < 2^32
   (exact i64 remainder, dividend-sign zero preserved); NaN operands
   and zero divisors answer NaN like the walker; everything else
   declines. Identical to Tier A's __js_mod. */
static double fmod(double a, double b) {{
  if (a != a || b != b) return 0.0 / 0.0;
  if (b == 0.0) return 0.0 / 0.0;
  if (a != __builtin_trunc(a) || __builtin_fabs(a) >= 4294967296.0) __builtin_trap();
  if (b != __builtin_trunc(b) || __builtin_fabs(b) >= 4294967296.0) __builtin_trap();
  long long r = (long long)a % (long long)b;
  if (r == 0 && a < 0.0) return -0.0;
  return (double)r;
}}

{helpers}
{prototypes}
{bodies}__attribute__((export_name("main")))
double gnosis_main({entry_params}) {{
  return {call};
}}
"#,
        helpers = NUMERIC_RUNTIME_HELPERS_C,
        prototypes = kernel.prototypes,
        bodies = kernel.bodies,
        entry_params = entry_params,
        call = call,
    ))
}

/// Locate a clang that can target wasm32-unknown-unknown. Apple's
/// system clang cannot; homebrew LLVM and versioned clangs can. The
/// probe actually compiles an empty module — existence is not ability.
pub fn wasm_clang() -> Option<PathBuf> {
    let mut candidates: Vec<PathBuf> = Vec::new();
    if let Ok(value) = std::env::var("GNOSIS_WASM_CLANG") {
        candidates.push(PathBuf::from(value));
    }
    candidates.push(PathBuf::from("/opt/homebrew/opt/llvm/bin/clang"));
    candidates.push(PathBuf::from("/usr/local/opt/llvm/bin/clang"));
    for versioned in ["clang-19", "clang-18", "clang-17", "clang"] {
        candidates.push(PathBuf::from(versioned));
    }
    candidates.into_iter().find(|candidate| {
        Command::new(candidate)
            .args([
                "--target=wasm32-unknown-unknown",
                "-nostdlib",
                "-x",
                "c",
                "-c",
                "-o",
            ])
            .arg(std::env::temp_dir().join("gnosis-wasm-clang-probe.o"))
            .arg("/dev/null")
            .output()
            .map(|out| out.status.success())
            .unwrap_or(false)
    })
}

/// Compile the freestanding C to a wasm32 module. Fails closed when
/// the program is outside the numeric-loop class or when no
/// wasm-capable clang exists — Tier A remains the toolchain-free path.
pub fn compile_wasm_via_c(source: &str, export_name: &str) -> Result<Vec<u8>> {
    let c_source = emit_freestanding_wasm_c(source, export_name)
        .with_context(|| format!("'{export_name}' is outside the certified numeric-loop class"))?;
    let clang = wasm_clang().context(
        "no wasm32-capable clang found (set GNOSIS_WASM_CLANG or install homebrew llvm); \
         use the toolchain-free Tier A emitter (aot_wasm) instead",
    )?;

    let dir = std::env::temp_dir().join(format!(
        "gnosis-wasm-via-c-{}-{:016x}",
        std::process::id(),
        crate::aot_c::fnv1a64(source.as_bytes()) ^ crate::aot_c::fnv1a64(export_name.as_bytes())
    ));
    fs::create_dir_all(&dir).context("create wasm-via-c temp dir")?;
    let c_path = dir.join("kernel.c");
    let wasm_path = dir.join("kernel.wasm");
    fs::write(&c_path, c_source).context("write freestanding C")?;

    let compile = Command::new(&clang)
        .args([
            "--target=wasm32-unknown-unknown",
            "-O2",
            "-fno-builtin",
            "-nostdlib",
            "-Wl,--no-entry",
            "-o",
        ])
        .arg(&wasm_path)
        .arg(&c_path)
        .output()
        .with_context(|| format!("invoke {} for wasm32", clang.display()))?;
    if !compile.status.success() {
        let _ = fs::remove_dir_all(&dir);
        bail!(
            "freestanding wasm32 compile failed: {}{}",
            String::from_utf8_lossy(&compile.stderr),
            String::from_utf8_lossy(&compile.stdout)
        );
    }
    let bytes = fs::read(&wasm_path).context("read compiled wasm module");
    let _ = fs::remove_dir_all(&dir);
    bytes
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn freestanding_c_has_no_includes_and_exports_main() {
        let c = emit_freestanding_wasm_c(
            "export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s = s + i; }\n  return s;\n}\n",
            "main",
        )
        .expect("sum loop is in the class");
        assert!(
            !c.contains("#include"),
            "freestanding shell must not include headers"
        );
        assert!(c.contains("export_name(\"main\")"));
        assert!(c.contains("__builtin_trap()"));
    }

    #[test]
    fn outside_class_refuses() {
        assert!(emit_freestanding_wasm_c(
            "export function main(n) { if (n < 2) return n; return main(n - 1) + main(n - 2); }\n",
            "main"
        )
        .is_none());
    }

    #[test]
    fn compiles_and_validates_when_toolchain_present() {
        if wasm_clang().is_none() {
            eprintln!("skipping wasm-via-c compile test: no wasm32-capable clang");
            return;
        }
        let bytes = compile_wasm_via_c(
            "export function main(n) {\n  let h = [0, 0, 0, 0, 0];\n  for (let i = 0; i < n; i++) { h[i % 5] += 1; }\n  let s = 0;\n  for (let j = 0; j < h.length; j++) { s += h[j] * (j + 1); }\n  return s;\n}\n",
            "main",
        )
        .expect("histogram compiles via clang");
        wasmparser::validate(&bytes).expect("clang-built module validates");

        // Zero imports — the freestanding contract.
        for payload in wasmparser::Parser::new(0).parse_all(&bytes) {
            if let wasmparser::Payload::ImportSection(reader) = payload.expect("parse") {
                assert_eq!(reader.count(), 0, "freestanding module must import nothing");
            }
        }
    }
}
